code.perFrame:
zoom = 0.9999;
rot = 0;
dx = 0;
dy = 0;
sx = 0.9999;
sy = 1;
warp = 0.01;
cx = 0.5;
cy = 0.5;
dt = 1/fps;;
dec_m = 1 - 6*dt; dec_s = 1 - 2*dt; dec_xs = 1-dt;;
vol = bass+mid+treb;;
vol_ = vol_*dec_m + (1-dec_m)*vol;;
is_beat = ((vol) > (.4+vol_+peak)) * ((time) > (t0+.2));;
t0 = is_beat*time + (1-is_beat)*t0;;
peak = is_beat * vol + (1-is_beat)*peak*dec_m;;
index = (index + is_beat) %32;;
index2 = (index2 + is_beat*bnot(index))%8;;
index3 = (index3 + is_beat* if(bnot(rand(8)%2),-1,1)*bnot(index%16))%6;;
num_res = 200; MINBPM = 50; MAXBPM = 200;;
tess = 0; maxind = 0; qavg = 0.001; i=0;;
loop (num_res,;
n = i*8;;
Freq  = (i/(num_res-1)+minbpm/(maxbpm-minbpm))*(maxbpm-minbpm)/60;;
Feder = sqr(Freq*6.2832); //Res.f = sqrt (Feder)/2pi (Hz);
Excite = (vol-vol_);;
gmegabuf (n+4) = gmegabuf(n+2); //alte pos;
gmegabuf (n+1) *= 1-0.2*dt; //damping;
EC_Steps = int (20*Freq*dt)+1;;
loop (EC_Steps, // Euler-Cauchy steps;
Kraft = Excite - Feder*gmegabuf(n + 2) ;;
gmegabuf (n+1) += Kraft         * dt/EC_Steps;;
gmegabuf (n+2) += gmegabuf(n+1) * dt/EC_Steps;;
);;
beatcos = gmegabuf(n+1);  beatsin = gmegabuf(n+2)*Freq*6.2832;;
quad = sqrt (pow(beatsin,2) + pow(beatcos,2));;
gmegabuf (n+3) = gmegabuf(n+3) *dec_m +  quad* (1-dec_m);;
if (gmegabuf(n+3) > gmegabuf (maxind*8+3), maxind =i,0);;
qavg = qavg+pow (gmegabuf(n+3),2);;
tess += beatsin* pow(gmegabuf(n+3)/gmegabuf(maxind*8+3),1)*5;;
i += 1;;
);;
qavg = sqrt (qavg/num_res);;
certain = gmegabuf(maxind*8+3)/qavg;;
dbl_beat = gmegabuf(maxind*8+2) * gmegabuf (maxind*8+4) < 0;;
bcount += dbl_beat;;
is_rbeat  = dbl_beat && (bcount%2==0);;
bcount2 += is_rbeat;;
is_rbeat2 =is_rbeat * (bcount%2==0);;
is_rbeat4 =is_rbeat * (bcount%4==0);;
is_rbeat8 =is_rbeat * (bcount%8==0);;
Freq  = (maxind/(num_res-1)+minbpm/(maxbpm-minbpm))*(maxbpm-minbpm)/60;;
Freq_ = Freq_* dec_s + (1-dec_s)*Freq;;
trad1 = trad1 + Freq_*dt*6.28/8;;
speed_ = speed_*dec_xs + (1-dec_xs)*Freq_*1.2;;
trig = (index==4) && is_beat;;
if (trig, dyang = 0.007*(rand(100)-50)* rand(10)/10, 0);;
pyr = pyr*dec_xs + (1-dec_xs)*dyang;;
pyr2 = pyr2*dec_xs + (1-dec_xs)*pyr;;
test = 0;;
fwx = fwx + (speed_)* sin(zang+test)*0.02/fps;;
fwy = fwy + (speed_)* cos(zang+test)*0.02/fps;;
//#############################################;
q5 = fwx; q6 = fwy; q7 =  0.3;;
yang = pyr2;;
trig = is_beat * (index==26);;
ran1 = if (trig,  int(rand(4))*-0.7/3-0.08, ran1);;
xang =  ran1;;
xang = -0.7 * (1.1-pow(cos(trad1/16),12));;
zang = zang + yang/6/fps*speed_/xang;;
pos_x = 0;;
pos_y = 0;;
pos_z = 0.24* (1+0.125*sin(2*zang))* aspecty*( 1.5- abs(xang)/2);;
q30 = .1/pos_z*cos(xang);;
ox = -pos_x; oy = -pos_y; oz = pos_z;;
mx = ox*cos(zang) - oy*sin(zang);;
my = ox*sin(zang) + oy*cos(zang);;
ox = mx;oy = my;;
mx = ox*cos(yang) + oz*sin(yang);;
mz = - ox*sin(yang) + oz*cos(yang);;
ox = mx;oz = mz;;
my = oy*cos(xang) - oz*sin(xang);;
mz = oy*sin(xang) + oz*cos(xang);;
oy = my;oz = mz;;
q11=ox; q12 = oy; q13 = oz; //Position;
//Vektor x nach rechts;
ox = 1; oy = 0; oz = 0;;
mx = ox*cos(zang) - oy*sin(zang);;
my = ox*sin(zang) + oy*cos(zang);;
ox = mx;oy = my;;
mx = ox*cos(yang) + oz*sin(yang);;
mz = - ox*sin(yang) + oz*cos(yang);;
ox = mx;oz = mz;;
my = oy*cos(xang) - oz*sin(xang);;
mz = oy*sin(xang) + oz*cos(xang);;
oy = my;oz = mz;;
q14=ox; q15 = oy; q16 = oz;;
//Vektor z nach hinten;
ox = 0; oy = 0; oz = 1;;;
mx = ox*cos(zang) - oy*sin(zang);;
my = ox*sin(zang) + oy*cos(zang);;
ox = mx;oy = my;;
mx = ox*cos(yang) + oz*sin(yang);;
mz = - ox*sin(yang) + oz*cos(yang);;
ox = mx;oz = mz;;
my = oy*cos(xang) - oz*sin(xang);;
mz = oy*sin(xang) + oz*cos(xang);;
oy = my;;
oz = mz;;
q17=ox; q18 = oy; q19 = oz;;
q20 = xang;;
q21 = yang;;
q22 = zang;;
q32 = aspecty;;
q4 = min(max(0,vol-vol_),4);;
q4 *= max(0,3*cos(trad1)-2)*8;;
q2 = is_rbeat;;
q3 = gmegabuf(maxind*8+2)>0;;
//q3 = bcount2%2;;
monitor = freq_*60;
